@using sv_b05589e254174cdb85e92a73f255d369.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IAsyncDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title">@WarehouseState.CurrentWarehouseName</h5>
        <p class="card-text">
            <span class="fs-4">Low Stock Alerts:</span>
            <span class="badge bg-danger fs-5 ms-2">@AlertService.LastKnownCount</span>
        </p>
        <p class="text-muted small">Polling every 10 seconds. Last update: @_lastUpdate?.ToString("HH:mm:ss")</p>
    </div>
</div>

@code {
    private CancellationTokenSource? _cts;
    private Action? _warehouseHandler;
    private Action? _alertHandler;
    private DateTime? _lastUpdate;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(OnWarehouseChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await StartPolling();
        }
    }

    private async Task StartPolling()
    {
        _cts?.Cancel();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        // Initial fetch
        await FetchAlerts();

        _ = Task.Run(async () =>
        {
            while (!token.IsCancellationRequested)
            {
                try
                {
                    await Task.Delay(TimeSpan.FromSeconds(10), token);
                    await InvokeAsync(async () =>
                    {
                        await FetchAlerts();
                    });
                }
                catch (OperationCanceledException)
                {
                    break;
                }
            }
        }, token);
    }

    private async Task FetchAlerts()
    {
        var count = await AlertService.GetLowStockCountAsync(WarehouseState.CurrentWarehouseId);
        _lastUpdate = DateTime.Now;
        // This notifies ALL subscribers (sidebar badge + this page)
        AlertService.UpdateCount(count);
    }

    private async Task OnWarehouseChanged()
    {
        // Warehouse changed — restart polling with new warehouse
        _cts?.Cancel();
        StateHasChanged();
        await StartPolling();
    }

    public async ValueTask DisposeAsync()
    {
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;

        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

